const SERVICE_FEE = 8;
function render(){renderFiltered();}

// ===== SEARCH =====
let srchQ='';
function doSearch(q){
  srchQ=q.trim();
  const cl=document.getElementById('srch-clear');
  if(cl) cl.style.display=srchQ?'block':'none';
  renderFiltered();
}
function clearSearch(){
  srchQ='';
  const inp=document.getElementById('srch');
  const cl=document.getElementById('srch-clear');
  if(inp) inp.value='';
  if(cl) cl.style.display='none';
  renderFiltered();
}
function renderFiltered(){
  const items=MENU.filter(p=>{
    if(p.brand!==brand) return false;
    if(!srchQ) return true;
    return p.n.includes(srchQ)||p.d.includes(srchQ);
  });
  const cont=document.getElementById('prods');
  if(items.length===0){
    cont.innerHTML=`<div class="no-results">😕 مفيش نتايج لـ "${srchQ}"</div>`;
    return;
  }
  cont.innerHTML=items.map(p=>{
    const q=cart[p.id]||0;
    const imgEl=p.img
      ? `<img src="${p.img}" class="pc-img" alt="${p.n}" loading="lazy" onmousedown="zoomImg(this)" ontouchstart="zoomImg(this)" onmouseup="unzoomImg(this)" ontouchend="unzoomImg(this)">`
      : `<div style="width:100%;height:100%;display:flex;align-items:center;justify-content:center;font-size:34px;min-height:90px;">${p.e}</div>`;
    return `<div class="pc ${q>0?'in-cart':''}" id="pc${p.id}">
      <div class="pc-img-wrap">${imgEl}<img src="${p.lg}" class="pc-logo-badge" alt=""></div>
      <div class="pcb">
        <div><div class="pcn">${p.n}</div><div class="pcd">${p.d}</div></div>
        <div class="pcf">
          <div class="pcp">${p.p} ج.م</div>
          <div class="qc">
            <button class="qb" onclick="chg(${p.id},-1)">−</button>
            <span class="qn" id="qn${p.id}">${q}</span>
            <button class="qb" onclick="chg(${p.id},1)">+</button>
          </div>
        </div>
      </div>
    </div>`;
  }).join('');
}

let cart={},brand='Bazooka',pay='cod',loc=null,seq=parseInt(localStorage.getItem('tyr_seq')||'0');
// ===== RENDER =====
function render(){
// لو المطعم مغلق
if(!RESTAURANT_STATUS[brand]) {
  // إظهار رسالة مغلق
  document.getElementById('closed-banner').style.display = 'block';
  // updateFab();
  document.getElementById('fab').style.display = 'none';
} else {
  document.getElementById('closed-banner').style.display = 'none';
  document.getElementById('fab').style.display = 'none';
}

  document.getElementById('prods').innerHTML=MENU.filter(p=>p.brand===brand).map(p=>{
    const q=cart[p.id]||0;
    const imgEl=p.img
      ? `<img src="${p.img}" class="pc-img" alt="${p.n}" loading="lazy" onmousedown="zoomImg(this)" ontouchstart="zoomImg(this)" onmouseup="unzoomImg(this)" ontouchend="unzoomImg(this)">`
      : `<div style="width:100%;height:100%;display:flex;align-items:center;justify-content:center;font-size:34px;min-height:90px;">${p.e}</div>`;
    return `<div class="pc ${q>0?'in-cart':''}" id="pc${p.id}">
      <div class="pc-img-wrap">${imgEl}<img src="${p.lg}" class="pc-logo-badge" alt=""></div>
      <div class="pcb">
        <div><div class="pcn">${p.n}</div><div class="pcd">${p.d}</div></div>
        <div class="pcf">
          <div class="pcp">${p.p} ج.م</div>
          <div class="qc">
            <button class="qb" onclick="chg(${p.id},-1)">−</button>
            <span class="qn" id="qn${p.id}">${q}</span>
            <button class="qb" onclick="chg(${p.id},1)">+</button>
          </div>
        </div>
      </div>
    </div>`;
  }).join('');
}

// ===== ZOOM =====
function zoomImg(el){el.classList.add('zoomed');}
function unzoomImg(el){el.classList.remove('zoomed');}

// ===== CART =====
function chg(id,d){
   if(!RESTAURANT_STATUS[brand]){
   toast('🔴 هذا المطعم مغلق حالياً', 1);
   return;
 }
  const n=Math.max(0,(cart[id]||0)+d);
  if(n===0)delete cart[id];else cart[id]=n;
  const qe=document.getElementById('qn'+id),ce=document.getElementById('pc'+id);
  if(qe)qe.textContent=n;
  if(ce)ce.className='pc '+(n>0?'in-cart':'');
  updateFab();updateBadges();
}

function updateBadges(){
  BRANDS.forEach(b=>{
    const c=MENU.filter(p=>p.brand===b).reduce((s,p)=>s+(cart[p.id]||0),0);
    const el=document.getElementById('cnt-'+b);
    if(el)el.textContent=c||'';
  });
}

function cartItems(){return Object.entries(cart).map(([id,q])=>{const p=MENU.find(x=>x.id==id);return p?{...p,q,t:p.p*q}:null}).filter(Boolean);}
function cartTotal(){return cartItems().reduce((s,i)=>s+i.t,0);}

function updateFab(){
  const fab=document.getElementById('fab'),it=cartItems(),c=it.reduce((s,i)=>s+i.q,0);
  if(c===0){fab.style.display='none';return;}
  fab.style.display='flex';
  document.getElementById('fc').textContent=c+' قطعة';
  document.getElementById('ft').textContent=' | '+cartTotal()+' ج.م';
}


// ===== BRAND =====
function setBrand(b,btn){
  brand=b;
  document.querySelectorAll('.btab').forEach(t=>t.classList.remove('active'));
  btn.classList.add('active');
  updateHeaderBrand(b);
  render();
}

function setBrandFromHeader(b){
  brand=b;
  document.querySelectorAll('.btab').forEach(t=>t.classList.toggle('active',t.dataset.brand===b));
  updateHeaderBrand(b);
  render();
}

function updateHeaderBrand(b){

  BRANDS.forEach(br=>{
    const check=document.getElementById('hbc-'+br);
    const logo=document.getElementById('hbl-'+br);
    if(check) check.style.display='block';
    if(logo) logo.classList.toggle('active-brand', br===b);
  });
}



// ===== STEPS =====
function goStep(n){
  if(n===2&&cartItems().length===0){toast('⚠️ اختر منتج على الأقل!',1);return;}
  if(n===3){
    const nm=document.getElementById('cn').value.trim();
    const ph=document.getElementById('cp').value.trim();
    const ad=document.getElementById('ca').value.trim();
    if(!nm||!ph||!ad){toast('⚠️ من فضلك اكمل بياناتك أولاً',1);return;}
    buildReview(nm,ph,ad);
  }
  document.querySelectorAll('.view').forEach((v,i)=>v.classList.toggle('active',i+1===n));
  [1,2,3].forEach(i=>{const b=document.getElementById('s'+i);b.className='sbtn'+(i===n?' active':i<n?' done':'');});
  window.scrollTo({top:0,behavior:'smooth'});
}
function buildReview(nm,ph,ad){
  const it=cartItems(),tot=cartTotal(),notes=document.getElementById('cno').value.trim();
  const payLbl=pay==='online'?'📲 انستاباي / فودافون كاش':'💵 عند الاستلام';
  const del=getDeliveryFee(ad);
  const serviceFee=6;
  const grandTotal=tot+del+serviceFee;

  document.getElementById('rl').innerHTML=it.map(i=>`
    <div class="ritem">
      <div><div class="rn">${i.e} ${i.n}</div><div class="rs">${BL[i.brand]} · ${i.q} × ${i.p} ج.م</div></div>
      <div class="rp">${i.t} ج.م</div>
    </div>`).join('');
   document.getElementById('tb').style.display='block';
document.getElementById('tb').innerHTML=`
  <div style="display:flex;justify-content:space-between;align-items:center;padding:6px 0;"><span>🛒 إجمالي الطلب</span><span>${tot} ج.م</span></div>
  <div style="display:flex;justify-content:space-between;align-items:center;padding:6px 0;"><span>🛵 رسوم التوصيل</span><span>${del} ج.م</span></div>
  <div style="display:flex;justify-content:space-between;align-items:center;padding:6px 0;"><span>🔧 رسوم الخدمة</span><span>${SERVICE_FEE} ج.م</span></div>
  <div style="display:flex;justify-content:space-between;align-items:center;padding:6px 0;"><span>المجموع الكلي</span><strong>${grandTotal} ج.م</strong></div>`;
 

  const payEx=pay==='online'?`<br><span style="font-size:12px;color:#1d4ed8">📲 رقم التحويل: ${PAY_NUM}</span>`:'';
  const locTxt=loc?` <a href="${loc.url}" target="_blank" style="color:var(--grn);font-size:11px">📍 خريطة</a>`:'';
  document.getElementById('ic').innerHTML=`👤 ${nm}<br>📱 ${ph}<br>🗺️ ${ad}${locTxt}<br>${payLbl}${payEx}${notes?`<br>📝 ${notes}`:''}`;
}


function setPay(t){
  pay=t;
  document.getElementById('pcc').className='pcard'+(t==='cod'?' acod':'');
  document.getElementById('pco').className='pcard'+(t==='online'?' aonline':'');
  document.getElementById('ob').style.display=t==='online'?'block':'none';
}

function getLoc(){
  const btn=document.getElementById('bl'),h=document.getElementById('lh'),icon=document.getElementById('loc-icon');
  if(!navigator.geolocation){toast('المتصفح لا يدعم الموقع',1);return;}
  btn.disabled=true;
  if(icon) icon.innerHTML='<path d="M12 4V1L8 5l4 4V6c3.31 0 6 2.69 6 6 0 1.01-.25 1.97-.7 2.8l1.46 1.46C19.54 15.03 20 13.57 20 12c0-4.42-3.58-8-8-8zm0 14c-3.31 0-6-2.69-6-6 0-1.01.25-1.97.7-2.8L5.24 7.74C4.46 8.97 4 10.43 4 12c0 4.42 3.58 8 8 8v3l4-4-4-4v3z" fill="#e8742a"/>';
  h.style.display='block';h.style.color='var(--tx2)';h.textContent='جاري تحديد موقعك...';
  navigator.geolocation.getCurrentPosition(
    pos=>{
      const la=pos.coords.latitude.toFixed(6),ln=pos.coords.longitude.toFixed(6);
      loc={la,ln,url:`https://maps.google.com/maps?q=${la},${ln}`};
      btn.disabled=false;
      if(icon) icon.innerHTML='<path d="M12 2C8.13 2 5 5.13 5 9c0 5.25 7 13 7 13s7-7.75 7-13c0-3.87-3.13-7-7-7zm0 9.5c-1.38 0-2.5-1.12-2.5-2.5s1.12-2.5 2.5-2.5 2.5 1.12 2.5 2.5-1.12 2.5-2.5 2.5z" fill="#1e7a45"/>';
      h.style.color='var(--grn)';h.textContent='✅ تم تحديد الموقع بنجاح';
      toast('📍 تم تحديد الموقع!');
    },
    ()=>{btn.disabled=false;if(icon) icon.innerHTML='<path d="M12 2C8.13 2 5 5.13 5 9c0 5.25 7 13 7 13s7-7.75 7-13c0-3.87-3.13-7-7-7zm0 9.5c-1.38 0-2.5-1.12-2.5-2.5s1.12-2.5 2.5-2.5 2.5 1.12 2.5 2.5-1.12 2.5-2.5 2.5z" fill="#dc2626"/>';h.style.color='#dc2626';h.textContent='❌ تعذّر الموقع، تأكد من الإذن';}
    ,{enableHighAccuracy:true,timeout:10000}
  );
}

// ===== FAB: تأكيد الطلب =====
function fabConfirm(){
  if(!RESTAURANT_STATUS[brand]){
    toast('🔴 هذا المطعم مغلق حالياً', 1);
    return;
  }
  const nm=document.getElementById('cn').value.trim();
  const ph=document.getElementById('cp').value.trim();
  const ad=document.getElementById('ca').value.trim();
  if(nm && ph && ad) goStep(3);
  else goStep(2);
}


// ===== RECEIPT =====
const brandEmojis={'Bazooka':'🍗','Karam El Sham':'🥙','B Laban':'🍮','Wahmy Burger':'🍔','Koshary Al Khedewy':'🥘​','Hawawshi Al Refaie':'🫓​','Saadaway Burger':'🍔​','Krebs':'🍕','Sliceno':'🍕'};

function getDeliveryFee(address) {
  const ad = address.toLowerCase();
  if (ad.includes('حي 12') || ad.includes('الحي 12')) return 20;
  if (ad.includes('حي 14') || ad.includes('الحي 14')) return 25;
  if (ad.includes('حي 15') || ad.includes('الحي 15')) return 30;
  if (ad.includes('حي 16') || ad.includes('الحي 16')) return 35;
  if (ad.includes('مجاورة 13') || ad.includes('مجاوره 13')) return 40;
  if (ad.includes('مجاورة 14') || ad.includes('مجاوره 14')) return 45;
  if (ad.includes('مجاورة 15') || ad.includes('مجاوره 15')) return 50;
  if (ad.includes('حي الاندلس ') || ad.includes('حي الاندلس')) return 10;
  return 40;
}
function buildReceipt(oid, nm, ph, ad, it, tot, payLbl, notes) {
  const del = getDeliveryFee(ad);
  const serviceFee = SERVICE_FEE;
  const grandTotal = tot + del + SERVICE_FEE;

  // تجميع المنتجات حسب البراند
  const byBrand = it.reduce((acc, i) => {
    (acc[i.brand] ??= []).push(i);
    return acc;
  }, {});

  // بناء تفاصيل المنتجات
  const itemsText = Object.entries(byBrand).map(([b, ps]) => {
    const lines = ps.map(i => `• ${i.n}\n  ${i.q} × ${i.p} ج.م = *${i.t} ج.م*`).join('\n');
    return `\n${brandEmojis[b]} *${BL[b]}*\n─────────────\n${lines}`;
  }).join('\n');

  // بناء قسم الدفع الأونلاين
  const onlinePayment = pay === 'online'
    ? `\n📲 *بيانات التحويل:*\nانستاباي / فودافون كاش: *${PAY_NUM}*\n✅ برجاء إرسال صورة الإيصال\n`
    : '';

  const divider = `━━━━━━━━━━━━━━━━━━━━\n`;
  const border  = `╔══════════════════╗\n`;

  return [
    `${border}║  ✈️  *طيار*  ✈️   ║\n╚══════════════════╝`,
    `\n🆔 *رقم الطلب:* ${oid}\n📅 ${new Date().toLocaleString('ar-EG')}`,
    divider,
    `👤 *الاسم:* ${nm}\n📱 *الموبايل:* ${ph}\n🗺️ *العنوان:* ${ad}`,
    loc ? `📍 *الخريطة:* ${loc.url}` : '',
    divider,
    `📦 *تفاصيل الطلب:*${itemsText}\n`,
    divider,
    `🛒 *إجمالي الطلب:* ${tot} ج.م\n🛵 *رسوم التوصيل:* ${del} ج.م\n🔧 *رسوم الخدمة:* ${SERVICE_FEE} ج.م`,
    divider,
    `💰 *الإجمالي الكلي: ${grandTotal} ج.م*\n💳 *طريقة الدفع:* ${payLbl}`,
    onlinePayment,
    notes ? `\n📝 *ملاحظات:* ${notes}` : '',
    divider,
    `⏱️ جاهز خلال *45 - 60 دقيقة*\n${border}║ شكراً لثقتك في طيار✈️  ║\n╚══════════════════╝`,
  ].filter(Boolean).join('\n');
}

function placeOrder(){
  if(!RESTAURANT_STATUS[brand]){
    toast('🔴 هذا المطعم مغلق حالياً', 1);
    return;
  }
  // باقي الكود زي ما هو
  const it=cartItems(),tot=cartTotal();
  const nm=document.getElementById('cn').value.trim();
  const ph=document.getElementById('cp').value.trim();
  const ad=document.getElementById('ca').value.trim();
  const notes=document.getElementById('cno').value.trim();
  seq++;localStorage.setItem('tyr_seq',seq);
  const oid='TYR-'+String(seq).padStart(4,'0');
  const payLbl=pay==='online'?'📲 انستاباي / فودافون كاش':'💵 الدفع عند الاستلام';
  const msg=buildReceipt(oid,nm,ph,ad,it,tot,payLbl,notes);
  window.open(`https://wa.me/${WA}?text=${encodeURIComponent(msg)}`,'_blank');
  // back end ===
  fetch('https://tayyar-8dc9c-default-rtdb.firebaseio.com/orders.json', {
    method: 'POST',
    headers: { 'Content-Type': 'application/json' },
    body: JSON.stringify({
        name: nm,
        phone: ph,
        address: ad,
        brand: brand,
        items: it,
        orderTotal: tot,
        delivery: getDeliveryFee(ad),
        service: SERVICE_FEE,
        grandTotal: tot + getDeliveryFee(ad) + SERVICE_FEE,
        payment: pay,
        orderNum: oid,
        notes: notes,
        timestamp: Date.now(),
        status: 'جديد'
    })
});
// back end ===
  showSuccess();
    fetch('https://tayyar-8dc9c-default-rtdb.firebaseio.com/orders.json', {
    method: 'POST',
    headers: { 'Content-Type': 'application/json' },
    body: JSON.stringify({
        name: nm,
        phone: ph,
        address: ad,
        brand: brand,
        items: it,
        orderTotal: tot,
        delivery: getDeliveryFee(ad),
        service: SERVICE_FEE,
        grandTotal: tot + getDeliveryFee(ad) + SERVICE_FEE,
        payment: pay,
        orderNum: oid,
        notes: notes,
        timestamp: Date.now(),
        status: 'جديد'
    })
});


}

let deliveryTimer=null;
function showSuccess(nm){
  document.querySelectorAll('.view').forEach(v=>v.classList.remove('active'));
  document.getElementById('steps-bar').style.display='none';
  document.getElementById('fab').style.display='none';
  const sw=document.getElementById('sw');
  sw.style.display='block';
  // Reset to loading state
  document.getElementById('loading-ring').style.display='block';
  document.getElementById('done-circle').style.display='none';
  document.getElementById('sw-title').textContent='تم إرسال طلبك! 🎉';
  document.getElementById('sw-msg').textContent='تم فتح واتساب برسالة طلبك الكامل';
  document.getElementById('timing-badge').textContent='⏱️ طلبك سيكون جاهز خلال 45 - 60 دقيقة';
  // After 65 seconds show delivered (for demo, use 65000ms)
  // In real use this would be much longer - using 70*60*1000 = 70 min
  // For demo we use 8 seconds
  if(deliveryTimer) clearTimeout(deliveryTimer);
  deliveryTimer=setTimeout(()=>{
    document.getElementById('loading-ring').style.display='none';
    document.getElementById('done-circle').style.display='flex';
    document.getElementById('sw-title').textContent='تم توصيل طلبك! ✅';
    document.getElementById('sw-msg').textContent=`شكراً ${nm || ''} على ثقتك في طيار 🚀`;
    document.getElementById('timing-badge').style.background='linear-gradient(135deg,#25d366,#128c7e)';
    document.getElementById('timing-badge').textContent='✅ تم التوصيل بنجاح!';
  }, 75*65*1000); // 70 minutes
}

function resetAll(){
  if(deliveryTimer) clearTimeout(deliveryTimer);
  cart={};loc=null;pay='cod';
  ['cn','cp','ca','cno'].forEach(id=>document.getElementById(id).value='');
  document.getElementById('lh').style.display='none';
  const locIcon=document.getElementById('loc-icon');
  if(locIcon) locIcon.innerHTML='<path d="M12 2C8.13 2 5 5.13 5 9c0 5.25 7 13 7 13s7-7.75 7-13c0-3.87-3.13-7-7-7zm0 9.5c-1.38 0-2.5-1.12-2.5-2.5s1.12-2.5 2.5-2.5 2.5 1.12 2.5 2.5-1.12 2.5-2.5 2.5z" fill="#7a6a54"/>';
  document.getElementById('ob').style.display='none';
  setPay('cod');
  document.getElementById('steps-bar').style.display='flex';
  document.getElementById('sw').style.display='none';
  document.getElementById('timing-badge').style.background='';
  brand='Bazooka';
  document.querySelectorAll('.btab').forEach((t,i)=>t.classList.toggle('active',i===0));
  updateHeaderBrand('Bazooka');
  goStep(1);render();updateFab();updateBadges();
}
// ===== مطعم آخر =====
let otherType='restaurant';
let otherLoc=null;
function selectOtherType(type) {
  otherType = type;

  // شيل selected من كل التابات
  ['restaurant', 'supermarket', 'pharmacy', ].forEach(t => {
    document.getElementById('tc-' + t).classList.remove('selected');
  });
  document.getElementById('tc-' + type).classList.add('selected');
  // خبي كل السكشنز الأول
  document.getElementById('pharmacy-sub').classList.remove('visible');
  document.getElementById('other-place-group').style.display = 'block';

  const pl = document.getElementById('other-place-label');
  const pi = document.getElementById('other-place-name');
  pi.value = '';

  if (type === 'pharmacy') {
    document.getElementById('pharmacy-sub').classList.add('visible');
    document.getElementById('other-place-group').style.display = 'none';


  } else if (type === 'restaurant') {
    pl.textContent = '📍 اسم المطعم *';
    pi.placeholder = 'مثال: مطعم الشيف محمود';

  } else if (type === 'supermarket') {
    pl.textContent = '📍 اسم السوبر ماركت *';
    pi.placeholder = 'مثال: سوبر ماركت الأهلي';
  }

  resetOtherErrors();
}

function selectPharmacy(name){
  document.querySelectorAll('.ph-opt').forEach(el=>el.classList.remove('selected'));
  event.currentTarget.classList.add('selected');
  document.getElementById('other-place-name').value=name;
}

function resetOtherErrors(){
  ['err-place','err-order','err-address'].forEach(id=>{
    const el=document.getElementById(id);
    if(el)el.classList.remove('show');
  });
  ['other-place-name','other-order','other-address'].forEach(id=>{
    const el=document.getElementById(id);
    if(el)el.classList.remove('field-err');
  });
}

function updateOtherFees(){
  const ad=(document.getElementById('other-address')?.value||'').trim();
  const box=document.getElementById('other-fees-box');
  if(!ad||ad.length<5){if(box)box.style.display='none';return;}
  const del=getDeliveryFee(ad);
  document.getElementById('other-del-val').textContent=del+' ج.م';
  document.getElementById('other-total-fees-val').textContent=(del+SERVICE_FEE)+' ج.م';
  if(box)box.style.display='block';
}

function getOtherLoc(){
  if(!navigator.geolocation){toast('المتصفح لا يدعم الموقع',1);return;}
  const btn=document.getElementById('other-loc-btn');
  const hint=document.getElementById('other-loc-hint');
  btn.disabled=true;
  hint.style.display='block';
  hint.style.color='var(--tx2)';
  hint.textContent='جاري تحديد موقعك...';
  navigator.geolocation.getCurrentPosition(
    pos=>{
      const la=pos.coords.latitude.toFixed(6),ln=pos.coords.longitude.toFixed(6);
      otherLoc={la,ln,url:`https://maps.google.com/maps?q=${la},${ln}`};
      btn.disabled=false;
      hint.style.color='green';
      hint.textContent='✅ تم تحديد الموقع بنجاح';
      toast('📍 تم تحديد الموقع!');
    },
    ()=>{
      btn.disabled=false;
      hint.style.color='red';
      hint.textContent='❌ تعذر تحديد الموقع';
    },
    {enableHighAccuracy:true,timeout:10000}
  );
}

function sendOtherOrder(){

  let valid=true;
  let placeName='';
  if(otherType==='pharmacy'){
    placeName=document.getElementById('other-place-name').value.trim();
    if(!placeName){
      document.getElementById('err-place').classList.add('show');
      valid=false;
    }
  }else{
    placeName=document.getElementById('other-place-name').value.trim();
    if(!placeName){
      document.getElementById('err-place').classList.add('show');
      document.getElementById('other-place-name').classList.add('field-err');
      valid=false;
    }
  }
  const orderDetails=document.getElementById('other-order').value.trim();
  if(!orderDetails){
    document.getElementById('err-order').classList.add('show');
    document.getElementById('other-order').classList.add('field-err');
    valid=false;
  }
  const address=document.getElementById('other-address').value.trim();
  if(!address){
    document.getElementById('err-address').classList.add('show');
    document.getElementById('other-address').classList.add('field-err');
    valid=false;
  }
  if(!valid)return;

  const del=getDeliveryFee(address);
  const serviceFee = SERVICE_FEE;
  const locLine=otherLoc?`\n📍 *الخريطة:* ${otherLoc.url}`:'';

  const typeLabels={restaurant:'🍽️ مطعم',supermarket:'🛒 سوبر ماركت',pharmacy:'💊 صيدلية',};
  const msg=`🚀 *طلب جديد من طيار*
━━━━━━━━━━━━━━━
${typeLabels[otherType]}: *${placeName}*
━━━━━━━━━━━━━━━
🛍️ *تفاصيل الطلب:*
${orderDetails}
━━━━━━━━━━━━━━━
🗺️ *العنوان:* ${address}${locLine}
🛵 *رسوم التوصيل:* ${del} ج.م
🔧 *رسوم الخدمة:* ${serviceFee} ج.م
💰 *إجمالي الرسوم:* ${del+SERVICE_FEE} ج.م
━━━━━━━━━━━━━━━
_تم الإرسال من تطبيق طيار_ 🛵`;

 const waNum=WA;
 

  window.open(`https://wa.me/${waNum}?text=${encodeURIComponent(msg)}`,'_blank');
  showOtherSuccess();
}

function showOtherSuccess(){
  document.getElementById('other-form').style.display='none';
  document.getElementById('pharmacy-sub').classList.remove('visible');
  const sw=document.getElementById('other-sw');
  sw.style.display='block';
}

function resetOtherForm(){
  otherLoc=null;
  document.getElementById('other-order').value='';
  document.getElementById('other-address').value='';
  document.getElementById('other-place-name').value='';
  document.getElementById('other-fees-box').style.display='none';
  document.getElementById('other-loc-hint').style.display='none';
  document.getElementById('other-loc-hint').textContent='';
  const sw=document.getElementById('other-sw');
  if(sw)sw.style.display='none';
  document.getElementById('other-form').style.display='block';
  selectOtherType('restaurant');
}

