// /    اخر/ 
let tT;
function toast(msg,err=0){
  const ex=document.querySelector('.tst');if(ex)ex.remove();clearTimeout(tT);
  const t=document.createElement('div');t.className='tst';t.textContent=msg;
  Object.assign(t.style,{position:'fixed',bottom:'100px',left:'50%',transform:'translateX(-50%)',background:err?'#dc2626':'#1a1208',color:'#fff',padding:'10px 20px',borderRadius:'12px',fontSize:'14px',fontWeight:'700',zIndex:'9999',fontFamily:'Tajawal,sans-serif',boxShadow:'0 4px 20px rgba(0,0,0,0.3)',whiteSpace:'nowrap'});
  document.body.appendChild(t);tT=setTimeout(()=>t.remove(),3000);
}

